/**
 * Generated by `createservice miniapp.GetOIDCClientService '--type=queries'`
 */

const { faker } = require('@faker-js/faker')
const dayjs = require('dayjs')

const { generateGqlQueries } = require('@open-condo/codegen/generate.gql')
const { generateGQLTestUtils } = require('@open-condo/codegen/generate.test.utils')
const { makeClient } = require('@open-condo/keystone/test.utils')
const { expectToThrowAccessDeniedErrorToResult, expectToThrowAuthenticationErrorToResult } = require('@open-condo/keystone/test.utils')

const { DEV_ENVIRONMENT } = require('@dev-portal-api/domains/miniapp/constants/publishing')
const { generatePayload } = require('@dev-portal-api/domains/miniapp/utils/serverSchema/oidcClient')
const {
    getAllOIDCClientsByTestClient,
    getOIDCClientByTestClient,
    createTestB2CApp,
    updateTestB2CApp,
    createTestB2BApp,
    createOIDCClientByTestClient,
    publishB2CAppByTestClient,
    changeOIDCClientByTestClient,
    B2CApp,
} = require('@dev-portal-api/domains/miniapp/utils/testSchema')
const {
    makeLoggedInAdminClient,
    makeLoggedInSupportClient,
    makeRegisteredAndLoggedInUser,
    makeLoggedInCondoAdminClient,
} = require('@dev-portal-api/domains/user/utils/testSchema')

const CondoB2CApp = generateGQLTestUtils(generateGqlQueries('B2CApp', '{ id importId oidcClient { id } }'))
const CondoOIDCClient = generateGQLTestUtils(generateGqlQueries('OidcClient', '{ id clientId payload isEnabled deletedAt importId importRemoteSystem }'))
 
describe('GetOIDCClientService', () => {
    let admin
    let support
    let b2cUser
    let b2cApp
    let b2bUser
    let b2bApp
    let anonymous
    let b2cOIDCClient
    let b2bOIDCClient
    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeLoggedInSupportClient()
        b2cUser = await makeRegisteredAndLoggedInUser()
        b2bUser = await makeRegisteredAndLoggedInUser()
        anonymous = await makeClient();

        [b2cApp] = await createTestB2CApp(b2cUser);
        [b2cOIDCClient] = await createOIDCClientByTestClient(b2cUser, b2cApp);

        [b2bApp] = await createTestB2BApp(b2bUser);
        [b2bOIDCClient] = await createOIDCClientByTestClient(b2bUser, b2bApp)
    })

    describe('OIDCClient', () => {
        describe('Access tests', () => {
            test('Admin can get OIDC client of any app', async () => {
                const [readClient] = await getOIDCClientByTestClient(admin, b2cApp)
                expect(readClient).toHaveProperty('id', b2cOIDCClient.id)
                expect(readClient).toHaveProperty('clientId', b2cOIDCClient.clientId)
                expect(readClient).toHaveProperty('redirectUri', b2cOIDCClient.redirectUri)
            })
            test('Support can get OIDC client of any app', async () => {
                const [readClient] = await getOIDCClientByTestClient(support, b2bApp)
                expect(readClient).toHaveProperty('id', b2bOIDCClient.id)
                expect(readClient).toHaveProperty('clientId', b2bOIDCClient.clientId)
                expect(readClient).toHaveProperty('redirectUri', b2bOIDCClient.redirectUri)
            })
            describe('User', () => {
                describe('Can get OIDC client of app he created',  () => {
                    test('For B2BApp', async () => {
                        const [readClient] = await getOIDCClientByTestClient(b2bUser, b2bApp)
                        expect(readClient).toHaveProperty('id', b2bOIDCClient.id)
                        expect(readClient).toHaveProperty('clientId', b2bOIDCClient.clientId)
                        expect(readClient).toHaveProperty('redirectUri', b2bOIDCClient.redirectUri)
                    })
                    test('For B2CApp', async () => {
                        const [readClient] = await getOIDCClientByTestClient(b2cUser, b2cApp)
                        expect(readClient).toHaveProperty('id', b2cOIDCClient.id)
                        expect(readClient).toHaveProperty('clientId', b2cOIDCClient.clientId)
                        expect(readClient).toHaveProperty('redirectUri', b2cOIDCClient.redirectUri)
                    })
                })
                test('Cannot for other apps', async () => {
                    await expectToThrowAccessDeniedErrorToResult(async () => {
                        await getOIDCClientByTestClient(b2bUser, b2cApp)
                    })
                    await expectToThrowAccessDeniedErrorToResult(async () => {
                        await getOIDCClientByTestClient(b2cUser, b2bApp)
                    })
                })
            })
            test('Anonymous cannot get any OIDC client', async () => {
                await expectToThrowAuthenticationErrorToResult(async () => {
                    await getOIDCClientByTestClient(anonymous, b2cApp)
                })
            })
        })
        describe('Logic tests', () => {
            test('Must not contain extra fields such as clientSecret', async () => {
                const [readClient] = await getOIDCClientByTestClient(b2cUser, b2cApp)
                expect(readClient).toEqual({
                    id: b2cOIDCClient.id,
                    clientId: b2cOIDCClient.clientId,
                    name: expect.any(String),
                    redirectUri: b2cOIDCClient.redirectUri,
                    isEnabled: expect.any(Boolean),
                })
            })
            describe('Resolution order', () => {
                /**
                 * Three candidates are set up using direct condo calls to decouple from dev-portal business logic:
                 *   - Candidate 1 (condoApp.oidcClient): a condo OIDCClient linked on the condoApp side
                 *   - Candidate 2 (oidcClientId field):  a condo OIDCClient referenced by dev-portal app.developmentOidcClientId
                 *   - Candidate 3 (legacy importId):     a condo OIDCClient with importId=app.id (created via CreateOIDCClientService)
                 *
                 * beforeEach recreates all 3 candidates fresh so each test is fully independent.
                 */
                let condoAdmin
                let user
                let app
                let condoApp
                let clientLinkedToCondoApp
                let clientFromOidcClientId
                let clientFromImportId

                beforeAll(async () => {
                    condoAdmin = await makeLoggedInCondoAdminClient()
                    user = await makeRegisteredAndLoggedInUser();

                    [app] = await createTestB2CApp(user)

                    // Publish once to create the condoApp — reused across all tests
                    await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
                    const refreshedApp = await B2CApp.getOne(user, { id: app.id })
                    condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId });

                    // Candidate 3: legacy importId client — created once since clientId=app.id is unique per app
                    [clientFromImportId] = await createOIDCClientByTestClient(user, app)
                })

                beforeEach(async () => {
                    const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }

                    // Candidate 2: a separate condo OIDCClient referenced via dev-portal oidcClientId field
                    const oidcClientIdCandidateId = faker.datatype.uuid()
                    clientFromOidcClientId = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender,
                        clientId: oidcClientIdCandidateId,
                        name: `[test] oidcClientId candidate for ${app.id}`,
                        payload: generatePayload(oidcClientIdCandidateId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await updateTestB2CApp(admin, app.id, { developmentOidcClientId: clientFromOidcClientId.id })

                    // Candidate 1: a separate condo OIDCClient linked directly on condoApp.oidcClient
                    const condoAppCandidateId = faker.datatype.uuid()
                    clientLinkedToCondoApp = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender,
                        clientId: condoAppCandidateId,
                        name: `[test] condoApp.oidcClient candidate for ${app.id}`,
                        payload: generatePayload(condoAppCandidateId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await CondoB2CApp.update(condoAdmin, condoApp.id, {
                        dv: 1,
                        sender,
                        oidcClient: { connect: { id: clientLinkedToCondoApp.id } },
                    })
                })

                test('Returns condoApp.oidcClient when all 3 candidates exist', async () => {
                    const [result] = await getOIDCClientByTestClient(admin, app)
                    expect(result).toHaveProperty('id', clientLinkedToCondoApp.id)
                })

                test('Falls back to oidcClientId when condoApp.oidcClient is deleted', async () => {
                    await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getOIDCClientByTestClient(admin, app)
                    expect(result).toHaveProperty('id', clientFromOidcClientId.id)
                })

                test('Falls back to importId client when condoApp.oidcClient and oidcClientId are deleted', async () => {
                    const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }
                    await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                        dv: 1,
                        sender,
                        deletedAt: dayjs().toISOString(),
                    })
                    await CondoOIDCClient.update(condoAdmin, clientFromOidcClientId.id, {
                        dv: 1,
                        sender,
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getOIDCClientByTestClient(admin, app)
                    expect(result).toHaveProperty('id', clientFromImportId.id)
                })

                test('Returns null when all candidates are deleted', async () => {
                    const sender = { dv: 1, fingerprint: faker.random.alphaNumeric(8) }
                    await CondoOIDCClient.update(condoAdmin, clientLinkedToCondoApp.id, {
                        dv: 1,
                        sender,
                        deletedAt: dayjs().toISOString(),
                    })
                    await CondoOIDCClient.update(condoAdmin, clientFromOidcClientId.id, {
                        dv: 1,
                        sender,
                        deletedAt: dayjs().toISOString(),
                    })
                    await CondoOIDCClient.update(condoAdmin, clientFromImportId.id, {
                        dv: 1,
                        sender,
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getOIDCClientByTestClient(admin, app)
                    expect(result).toBeNull()
                })
            })
        })
    })

    describe('allOIDCClients', () => {
        describe('Access tests', () => {
            test('Anonymous cannot call allOIDCClients', async () => {
                await expectToThrowAuthenticationErrorToResult(async () => {
                    await getAllOIDCClientsByTestClient(anonymous)
                })
            })
            test('Returns empty array for user with no apps', async () => {
                const emptyUser = await makeRegisteredAndLoggedInUser()
                const [result] = await getAllOIDCClientsByTestClient(emptyUser)
                expect(result).toEqual([])
            })
            test('Authenticated user can call allOIDCClients', async () => {
                const [result] = await getAllOIDCClientsByTestClient(b2cUser)
                expect(Array.isArray(result)).toBe(true)
            })
        })
        describe('Logic tests', () => {
            let condoAdmin

            beforeAll(async () => {
                condoAdmin = await makeLoggedInCondoAdminClient()
            })

            describe('Isolation', () => {
                let user
                let otherUser
                let ownedApp
                let otherApp
                let ownedClient
                let otherClient

                beforeAll(async () => {
                    user = await makeRegisteredAndLoggedInUser()
                    otherUser = await makeRegisteredAndLoggedInUser();

                    [ownedApp] = await createTestB2CApp(user);
                    [ownedClient] = await createOIDCClientByTestClient(user, ownedApp);

                    [otherApp] = await createTestB2CApp(otherUser);
                    [otherClient] = await createOIDCClientByTestClient(otherUser, otherApp)
                })
                
                test('Returns only OIDC clients for apps the user owns', async () => {
                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(ownedClient.id)
                    expect(ids).not.toContain(otherClient.id)
                })

                test('Other user does not see this user\'s clients', async () => {
                    const [result] = await getAllOIDCClientsByTestClient(otherUser)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(otherClient.id)
                    expect(ids).not.toContain(ownedClient.id)
                })

                test('App with no OIDC client does not produce an entry in results', async () => {
                    const user2 = await makeRegisteredAndLoggedInUser()
                    const [appWithClient] = await createTestB2CApp(user2)
                    const [appWithoutClient] = await createTestB2CApp(user2)
                    const [client] = await createOIDCClientByTestClient(user2, appWithClient)

                    const [result] = await getAllOIDCClientsByTestClient(user2)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(client.id)
                    // result contains OIDCClient ids, not app ids — verify count is exactly 1
                    expect(result).toHaveLength(1)
                    void appWithoutClient
                })

                test('Each returned client has exactly the expected fields (no extra fields like clientSecret)', async () => {
                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const client = result.find(c => c.id === ownedClient.id)
                    expect(client).toEqual({
                        id: ownedClient.id,
                        clientId: ownedClient.clientId,
                        name: expect.any(String),
                        redirectUri: ownedClient.redirectUri,
                        isEnabled: expect.any(Boolean),
                    })
                })
                test('Each client must be unique', async () => {
                    const [thirdApp] = await createTestB2CApp(user)
                    await changeOIDCClientByTestClient(user, thirdApp, ownedClient.id)
                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const clientIds = new Set(result.map(c => c.id))
                    expect(result).toHaveLength(clientIds.size)
                })
                test('Must return clients from user owned apps, which is not currently used by user owned app', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [secondApp] = await createTestB2CApp(user)
                    const [client] = await createOIDCClientByTestClient(user, app)
                    const [secondClient] = await createOIDCClientByTestClient(user, secondApp)
                    await changeOIDCClientByTestClient(user, app, secondClient.id)
                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result).toHaveLength(2)
                    expect(result.map(c => c.id)).toEqual(expect.arrayContaining([client.id, secondClient.id]))
                })
            })

            describe('Step 3 — legacy importId (via CreateOIDCClientService)', () => {
                test('Returns client matched by importId for B2CApp', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [client] = await createOIDCClientByTestClient(user, app)

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result.map(c => c.id)).toContain(client.id)
                })

                test('Returns client matched by importId for B2BApp', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2BApp(user)
                    const [client] = await createOIDCClientByTestClient(user, app)

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result.map(c => c.id)).toContain(client.id)
                })

                test('Does not include deleted importId client', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [client] = await createOIDCClientByTestClient(user, app)

                    await CondoOIDCClient.update(condoAdmin, client.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result.map(c => c.id)).not.toContain(client.id)
                })
            })

            describe('Step 2 — explicit oidcClientId field', () => {
                test('Returns client matched by oidcClientId when set on app', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)

                    const clientId = faker.datatype.uuid()
                    const oidcClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId,
                        name: `[test] oidcClientId step2 for ${app.id}`,
                        payload: generatePayload(clientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await updateTestB2CApp(admin, app.id, { developmentOidcClientId: oidcClient.id })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result.map(c => c.id)).toContain(oidcClient.id)
                })

                test('Returns oidcClientId and importId client when both exist', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [importIdClient] = await createOIDCClientByTestClient(user, app)

                    const clientId = faker.datatype.uuid()
                    const oidcClientIdClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId,
                        name: `[test] oidcClientId preferred for ${app.id}`,
                        payload: generatePayload(clientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await updateTestB2CApp(admin, app.id, { developmentOidcClientId: oidcClientIdClient.id })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    // ImportId client is also returned, since it was created via dev-portal, but not used right now
                    expect(result).toHaveLength(2)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(oidcClientIdClient.id)
                    expect(ids).toContain(importIdClient.id)
                })

                test('Falls back to importId client when oidcClientId client is deleted', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [importIdClient] = await createOIDCClientByTestClient(user, app)

                    const clientId = faker.datatype.uuid()
                    const oidcClientIdClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId,
                        name: `[test] oidcClientId deleted for ${app.id}`,
                        payload: generatePayload(clientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await updateTestB2CApp(admin, app.id, { developmentOidcClientId: oidcClientIdClient.id })
                    await CondoOIDCClient.update(condoAdmin, oidcClientIdClient.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(importIdClient.id)
                    expect(ids).not.toContain(oidcClientIdClient.id)
                })
            })

            describe('Step 1 — condoApp.oidcClient', () => {
                test('Returns client linked on condoApp.oidcClient when published', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)

                    await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
                    const refreshedApp = await B2CApp.getOne(user, { id: app.id })
                    const condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId })

                    const clientId = faker.datatype.uuid()
                    const linkedClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId,
                        name: `[test] condoApp linked for ${app.id}`,
                        payload: generatePayload(clientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await CondoB2CApp.update(condoAdmin, condoApp.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        oidcClient: { connect: { id: linkedClient.id } },
                    })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result.map(c => c.id)).toContain(linkedClient.id)
                })

                test('Prefers condoApp.oidcClient over oidcClientId', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [importIdClient] = await createOIDCClientByTestClient(user, app)

                    await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
                    const refreshedApp = await B2CApp.getOne(user, { id: app.id })
                    const condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId })

                    const oidcClientIdClientId = faker.datatype.uuid()
                    const oidcClientIdClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId: oidcClientIdClientId,
                        name: `[test] oidcClientId for ${app.id}`,
                        payload: generatePayload(oidcClientIdClientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await updateTestB2CApp(admin, app.id, { developmentOidcClientId: oidcClientIdClient.id })

                    const condoLinkedClientId = faker.datatype.uuid()
                    const condoLinkedClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId: condoLinkedClientId,
                        name: `[test] condoApp.oidcClient for ${app.id}`,
                        payload: generatePayload(condoLinkedClientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await CondoB2CApp.update(condoAdmin, condoApp.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        oidcClient: { connect: { id: condoLinkedClient.id } },
                    })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    expect(result).toHaveLength(2)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(condoLinkedClient.id)
                    expect(ids).not.toContain(oidcClientIdClient.id)
                    expect(ids).toContain(importIdClient.id)
                })

                test('Falls back to step 2/3 when condoApp.oidcClient is deleted', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [app] = await createTestB2CApp(user)
                    const [importIdClient] = await createOIDCClientByTestClient(user, app)

                    await publishB2CAppByTestClient(user, app, { info: true }, DEV_ENVIRONMENT)
                    const refreshedApp = await B2CApp.getOne(user, { id: app.id })
                    const condoApp = await CondoB2CApp.getOne(condoAdmin, { id: refreshedApp.developmentExportId })

                    const linkedClientId = faker.datatype.uuid()
                    const linkedClient = await CondoOIDCClient.create(condoAdmin, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        clientId: linkedClientId,
                        name: `[test] condoApp.oidcClient deleted for ${app.id}`,
                        payload: generatePayload(linkedClientId, faker.internet.url() + '/'),
                        isEnabled: true,
                    })
                    await CondoB2CApp.update(condoAdmin, condoApp.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        oidcClient: { connect: { id: linkedClient.id } },
                    })
                    await CondoOIDCClient.update(condoAdmin, linkedClient.id, {
                        dv: 1,
                        sender: { dv: 1, fingerprint: faker.random.alphaNumeric(8) },
                        deletedAt: dayjs().toISOString(),
                    })

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(importIdClient.id)
                    expect(ids).not.toContain(linkedClient.id)
                })
            })

            describe('Multiple apps', () => {
                test('Returns clients for both B2BApp and B2CApp in one call', async () => {
                    const user = await makeRegisteredAndLoggedInUser()
                    const [b2cApp] = await createTestB2CApp(user)
                    const [b2bApp] = await createTestB2BApp(user)
                    const [b2cClient] = await createOIDCClientByTestClient(user, b2cApp)
                    const [b2bClient] = await createOIDCClientByTestClient(user, b2bApp)

                    const [result] = await getAllOIDCClientsByTestClient(user)
                    const ids = result.map(c => c.id)
                    expect(ids).toContain(b2cClient.id)
                    expect(ids).toContain(b2bClient.id)
                })
            })
        })
    })
})